// ======================================================
// PHASE 1: USER SUBMISSION (/reportar)
// ======================================================
// 1. Intercept the submission call
cy.intercept('POST', `${API_URL}/reports`, {
  statusCode: 201,
  body: {
    message: 'Report created',
    report_id: NEW_REPORT_ID
  }
}).as('submitReport');
// 2. Mock Geolocation logic before page load
cy.visit('/reportar', {
  onBeforeLoad(win) {
    cy.stub(win.navigator.geolocation, 'getCurrentPosition').callsFake(cb => {
      return cb({
        coords: {
          latitude: MOCK_COORDS.lat,
          longitude: MOCK_COORDS.lng
        }
      });
    });
  }
});
// 3. Fill out the form
cy.get('input[name="name"]').type(REPORT_DATA.reporter_name);
cy.get('input[name="date"]').type(REPORT_DATA.date);
cy.get('textarea[name="description"]').type(REPORT_DATA.description);
// Select dropdown (Pueblo)
cy.get('select[name="pueblo"]').select(REPORT_DATA.city);
// 4. Handle Geolocation Permission Checkbox
cy.get('input[name="allowLocation"]').check();
// Verify Map appears (Component logic: showMap becomes true)
cy.get('.esri-view-root canvas', {
  timeout: 20000
}).should('have.length.greaterThan', 0);
// 5. Submit Form
cy.contains('button', 'Enviar Reporte').click();
// 6. Verify API Request Payload
cy.wait('@submitReport').then(interception => {
  const body = interception.request.body;
  expect(body.city).to.equal(REPORT_DATA.city);
  expect(body.description).to.equal(REPORT_DATA.description);
  // Coordinates are passed as strings in your code
  expect(parseFloat(body.latitude)).to.be.closeTo(MOCK_COORDS.lat, 0.001);
});
// 7. Verify Success UI
cy.contains('¡Reporte e imágenes enviados exitosamente!').should('be.visible');
// ======================================================
// PHASE 2: ADMIN VALIDATION (/cms)
// ======================================================
// 1. Mock Login & Auth API calls
// Build valid fake JWT
const fakeHeader = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9';
const fakePayload = 'eyJzdWIiOjEsImVtYWlsIjoiYWRtaW5AdGVzdC5jb20ifQ';
const fakeSignature = 'signature';
const adminToken = `${fakeHeader}.${fakePayload}.${fakeSignature}`;
const adminId = 1;
// Intercepts
cy.intercept('POST', `${API_URL}/admins/login`, {
  statusCode: 200,
  body: {
    token: adminToken
  }
}).as('adminLogin');
cy.intercept('GET', `${API_URL}/admins/${adminId}`, {
  statusCode: 200,
  body: {
    id: adminId,
    email: 'admin@test.com',
    isAuthorized: 1
  }
}).as('checkAuth');
// Intercept Fetching Reports (CMSReports.jsx)
cy.intercept('GET', `${API_URL}/reports`, {
  statusCode: 200,
  body: [pendingReportObj] // Return our pending report
}).as('getReports');
// Intercept Creating Landslide (Triggered when validating)
cy.intercept('POST', `${API_URL}/landslides`, {
  statusCode: 201,
  body: {
    id: NEW_LANDSLIDE_ID
  }
}).as('createLandslide');
// Intercept Updating Report (Final validation step)
cy.intercept('PUT', `${API_URL}/reports/${NEW_REPORT_ID}`, {
  statusCode: 200,
  body: {
    message: 'Updated'
  }
}).as('updateReport');
// 2. Perform Login Flow
cy.visit('/cms/login');
cy.get('input[placeholder="Correo Electrónico"]').type('admin@test.com');
cy.get('input[placeholder="Contraseña"]').type('password123');
cy.get('button[type="submit"]').click();
cy.wait('@adminLogin');
// Note: Your CMSLogin extracts ID from JWT. 
// Since we provided a dummy token, your `atob` logic might fail in the real app if the token isn't a valid JWT structure.
// **Workaround for test:** Manually set localStorage and visit dashboard if login logic is strict about JWT format.
// However, assuming `checkAuth` passes or we bypass:
// Bypass UI login complexity by seeding storage (Mocking a valid JWT payload structure is annoying)
// Let's assume the login worked or force the visit:
cy.visit('/cms/reportes', {
  onBeforeLoad(win) {
    // Mock a token that decodes to ID 1 to satisfy `getPayloadFromToken`
    // {"sub":1,"email":"admin@test.com"} base64 encoded
    const fakePayload = 'eyJzdWIiOjEsImVtYWlsIjoiYWRtaW5AdGVzdC5jb20ifQ==';
    const fakeToken = `header.${fakePayload}.signature`;
    win.localStorage.setItem('cmsAdmin', fakeToken);
  }
});
// 3. Reports Dashboard Actions
cy.wait('@getReports'); // Wait for table to load
cy.contains('Reportes Ciudadanos').should('be.visible');
// Verify the report is in the table as "Pendiente"
cy.contains('td', REPORT_DATA.city).parent().within(() => {
  cy.contains('Pendiente').should('be.visible');
  cy.get('button[title="Validar / Editar"]').click();
});
// 4. Validate the Report in the Form
cy.contains('Validar Reporte').should('be.visible');
// Change status to Validated
cy.get('select[name="is_validated"]').select('1'); // 1 = Validado
// Check that lat/long are filled (required for validation)
cy.get('input[name="latitude"]').should('have.value', MOCK_COORDS.lat.toString());
// Save
cy.contains('button', 'Guardar Cambios').click();
// Handle SweetAlert Confirmation
cy.get('.swal2-confirm').click();
// 5. Verify Requests were made
// Expect creation of landslide record
cy.wait('@createLandslide').then(interception => {
  expect(interception.request.body.latitude).to.eq(MOCK_COORDS.lat);
});
// Expect update of report record linking it to landslide
cy.wait('@updateReport').then(interception => {
  expect(interception.request.body.is_validated).to.eq(1);
  expect(interception.request.body.landslide_id).to.eq(NEW_LANDSLIDE_ID);
});
// Verify Success Alert
cy.contains('Reporte actualizado').should('be.visible');
